onClick:
{{
  (async function() {
    // 1. Check if any customers are selected in the table
    if (!tblCustomers.selectedRows || tblCustomers.selectedRows.length === 0) {
      showAlert('Please select at least one customer from the table first.', 'warning');
      return;
    }

    // 2. Check if at least one update field (DSE or Route) is selected
    if (!SelectNewDSE.selectedOptionValue && !SelectNewRoute.selectedOptionValue) {
      showAlert('Please select a new DSE or a new Route to update.', 'warning');
      return;
    }

    // 3. Run the API
    try {
      await BulkEditCustomersAPI.run();

      // 4. Show success message showing how many were updated
      showAlert('Successfully updated ' + tblCustomers.selectedRows.length + ' customers!', 'success');

      // 5. Refresh the customers table so the new DSE/Route shows up
      await getCustomers.run();

      // 6. Clear table selection after a successful bulk edit
      resetWidget('tblCustomers', true);

    } catch (error) {
      showAlert('Failed to bulk edit: ' + error.message, 'error');
    }
  })()
}}
